svg.script:
(async function() {
  const frame = document.getElementById('main-frame');
  const repoBase = window.location.href.substring(0, window.location.href.lastIndexOf('/') + 1);

  async function renderPage(url) {
    try {
      const cacheBuster = "?cb=" + new Date().getTime();
      const response = await fetch(url + cacheBuster);
      if (!response.ok) throw new Error("HTTP " + response.status);

      let html = await response.text();

      if (url.includes('index.html')) {
        const matchTitle = html.match(/<title>(.*?)<\/title>/i);
        if (matchTitle) document.title = matchTitle[1];

        const matchFavicon = html.match(/<link.*rel=["'](?:shortcut )?icon["'].*href=["'](.*?)["']/i);
        if (matchFavicon) {
            let link = document.querySelector("link[rel*='icon']") || document.createElement('link');
            link.type = 'image/x-icon';
            link.rel = 'shortcut icon';
            link.href = matchFavicon[1].startsWith('http') ? matchFavicon[1] : repoBase + matchFavicon[1];
            document.head.appendChild(link);
        }
      }

      const scriptInjector = `
        <base href="${repoBase}">
        <script>
          document.addEventListener('click', e => {
            const a = e.target.closest('a');
            if (a && a.href.startsWith('${repoBase}') && !a.target) {
              e.preventDefault();
              window.parent.postMessage({type: 'NAV', url: a.href}, '*');
            }
          });
        <\/script>
      `;

      html = html.replace('<head>', '<head>' + scriptInjector);

      const blob = new Blob([html], { type: 'text/html' });
      frame.src = URL.createObjectURL(blob);
    } catch (err) {
      frame.srcdoc = "<body style='background:#0b0a16;color:white;font-family:sans-serif;display:grid;place-items:center;height:100vh;'><div><h2>Load Failed</h2><p>"+err+"</p></div></body>";
    }
  }

  window.addEventListener('message', e => {
    if (event.data.type === 'NAV') renderPage(event.data.url);
  });

  renderPage(repoBase + 'index.html');
})();
